 44→export const createChapterService = async (storyId, userId, title) => {
 45→    if (!storyId || !userId) {
 46→        throw { status: 400, error: 'storyId and userId are required' };
 47→    }
 48→
 49→    await verifyStoryOwnership(storyId, userId);
 50→
 51→    // Get next chapter number
 52→    const { data: lastChapter } = await supabase
 53→        .from('chapters')
 54→        .select('chapter_number')
 55→        .eq('story_id', storyId)
 56→        .order('chapter_number', { ascending: false })
 57→        .limit(1)
 58→        .maybeSingle();
 59→
 60→    const nextNumber = (lastChapter?.chapter_number || 0) + 1;
 61→
 62→    const { data, error } = await supabase
 63→        .from('chapters')
 64→        .insert({
 65→            story_id: storyId,
 66→            chapter_number: nextNumber,
 67→            title: (title || 'Untitled Chapter').trim(),
 68→        })
 69→        .select('id, story_id, title, chapter_number, status, word_count, created_at, updated_at')
 70→        .single();
 71→
 72→    if (error) {
 73→        console.error('supabase error creating chapter:', error.message);
 74→        throw { status: 500, error: 'failed to create chapter' };
 75→    }
 76→
 77→    return data;
