152→export const updateChapterService = async (storyId, chapterId, userId, updates) => {
153→    if (!storyId || !chapterId || !userId) {
154→        throw { status: 400, error: 'storyId, chapterId, and userId are required' };
155→    }
156→
157→    await verifyStoryOwnership(storyId, userId);
158→
159→    const updateData = {};
160→
161→    if (updates.title !== undefined) {
162→        updateData.title = (updates.title || 'Untitled Chapter').trim();
163→    }
164→    if (updates.content !== undefined) {
165→        // Store as JSONB – parse if string to validate, then store parsed
166→        let parsed = updates.content;
167→        if (typeof parsed === 'string') {
168→            try { parsed = JSON.parse(parsed); } catch {
169→                throw { status: 400, error: 'invalid content JSON' };
170→            }
171→        }
172→        updateData.content = parsed;
173→        updateData.word_count = extractWordCount(parsed);
174→    }
175→    if (updates.status !== undefined) {
176→        if (!['draft', 'published'].includes(updates.status)) {
177→            throw { status: 400, error: 'invalid chapter status' };
178→        }
179→        updateData.status = updates.status;
180→        if (updates.status === 'published') {
181→            // Set published_at only on first publish
182→            const { data: current } = await supabase
183→                .from('chapters')
184→                .select('published_at')
185→                .eq('id', chapterId)
186→                .single();
187→            if (!current?.published_at) {
188→                updateData.published_at = new Date().toISOString();
189→
190→                // Non-fatal: record publish for writing streak (first publish only)
191→                try {
192→                    const { recordPublishForStreak } = await import('./streakService.js');
193→                    recordPublishForStreak(userId).catch(err =>
194→                        console.error('non-fatal: streak record failed:', err?.message || err)
195→                    );
196→                } catch (streakErr) {
197→                    console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
198→                }
199→            }
200→        }
201→    }
202→
203→    if (Object.keys(updateData).length === 0) {
204→        throw { status: 400, error: 'no valid fields to update' };
205→    }
206→
207→    const { data, error } = await supabase
208→        .from('chapters')
209→        .update(updateData)
210→        .eq('id', chapterId)
211→        .eq('story_id', storyId)
212→        .select('id, story_id, title, chapter_number, status, word_count, created_at, updated_at')
213→        .single();
214→
215→    if (error) {
216→        console.error('supabase error updating chapter:', error.message);
217→        throw { status: 500, error: 'failed to update chapter' };
218→    }
219→
220→    return data;
221→};
