 49→    const [hasChanges, setHasChanges] = useState(false);
 50→    const saveTimerRef = useRef(null);
 51→    const uploadedImgPathsRef = useRef([]);
 52→
 53→    // Load existing content into editor
 54→    useEffect(() => {
 55→        if (chapter?.content && editor) {
 56→            try {
 57→                const content = typeof chapter.content === 'string'
 58→                    ? chapter.content
 59→                    : JSON.stringify(chapter.content);
 60→                const state = editor.parseEditorState(content);
 61→                editor.setEditorState(state);
 62→            } catch (err) {
 63→                console.error('Failed to load chapter content:', err);
 64→            }
 65→        }
 66→    }, [chapter?.id, editor]);
 67→
 68→    const onchange = useCallback((state) => {
 69→        const jsonStr = JSON.stringify(state.toJSON());
 70→        setEditorState(jsonStr);
 71→        setHasChanges(true);
 72→
 73→        state.read(() => {
 74→            const root = $getRoot();
 75→            const text = root.getTextContent().trim();
 76→            setWordCount(text ? text.split(/\s+/).length : 0);
 77→        });
 78→    }, []);
 79→
 80→    // Auto-save every 30 seconds
 81→    useEffect(() => {
 82→        if (!hasChanges || !editorState) return;
 83→
 84→        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
 85→        saveTimerRef.current = setTimeout(() => {
 86→            handleSave(false);
 87→        }, 30000);
 88→
 89→        return () => {
 90→            if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
 91→        };
 92→    }, [editorState, hasChanges]);
 93→
 94→    const handleSave = async (showFeedback = true) => {
 95→        if (!editorState) return;
