  1→import supabase from "./supabase.js";
  2→import { buildPathMatcher, listVariantPathsForDeletion } from "../utils/mediaVariants.js";
  3→
  4→const ALLOWED_MEDIA_BUCKETS = new Set(["background", "journal-images", "avatars"]);
  5→
  6→const normalizeUrl = (url = "") => {
  7→    if(typeof url !== "string" || !url){
  8→        return "";
  9→    }
 10→
 11→    try {
 12→        const parsed = new URL(url);
 13→        return `${parsed.origin}${parsed.pathname}`;
 14→    } catch {
 15→        return "";
 16→    }
 17→};
 18→
 19→const extractBackgroundImageUrl = (background) => {
 20→    if(!background || typeof background !== "object"){
 21→        return "";
 22→    }
 23→
 24→    const rawBackgroundImage = background?.backgroundImage;
 25→    if(typeof rawBackgroundImage !== "string"){
 26→        return "";
 27→    }
 28→
 29→    const match = rawBackgroundImage.match(/url\(['"]?(.*?)['"]?\)/i);
 30→    const extractedUrl = match?.[1] || rawBackgroundImage;
 31→    return normalizeUrl(extractedUrl);
 32→};
 33→
 34→const doesUrlMatchDeletedPath = (candidateUrl, bucket, path, deletedPublicUrl = "", providedUrl = "") => {
 35→    const normalizedCandidateUrl = normalizeUrl(candidateUrl);
 36→    if(!normalizedCandidateUrl){
 37→        return false;
 38→    }
 39→
 40→    const normalizedDeletedPublicUrl = normalizeUrl(deletedPublicUrl);
 41→    const normalizedProvidedUrl = normalizeUrl(providedUrl);
 42→
 43→    if(normalizedDeletedPublicUrl && normalizedCandidateUrl === normalizedDeletedPublicUrl){
 44→        return true;
 45→    }
 46→
 47→    if(normalizedProvidedUrl && normalizedCandidateUrl === normalizedProvidedUrl){
 48→        return true;
 49→    }
 50→
 51→    const variantMatcher = buildPathMatcher(path);
 52→    if(variantMatcher){
 53→        return variantMatcher.test(normalizedCandidateUrl);
 54→    }
 55→
 56→    return normalizedCandidateUrl.endsWith(`/${bucket}/${path}`);
 57→};
