 59→export const deleteJournalImageService = async(userId, filepath) =>{
 60→    if(!userId){
 61→        console.error('userId is undefined');
 62→        throw {status: 400, error:'userId is undefined'};
 63→    }
 64→    
 65→    if(!filepath){
 66→        console.error('filepath is undefined');
 67→        throw {status: 400, error: 'filepath is undefined'}
 68→    }
 69→
 70→    const normalizedPaths = (Array.isArray(filepath) ? filepath : [filepath])
 71→        .filter((path) => typeof path === 'string' && path.trim())
 72→        .flatMap((path) => listVariantPathsForDeletion(path.trim()));
 73→
 74→    if(normalizedPaths.length === 0){
 75→        console.error('filepath is undefined');
 76→        throw {status: 400, error: 'filepath is undefined'};
 77→    }
 78→
 79→    const expectedPrefix = `user_id_${userId}/`;
 80→    const hasForbiddenPath = normalizedPaths.some((path) => !path.startsWith(expectedPrefix));
 81→    if(hasForbiddenPath){
 82→        console.error('forbidden journal image path for user');
 83→        throw {status: 403, error: 'forbidden journal image path'};
 84→    }
 85→
 86→    const {error} = await supabase.storage
 87→        .from('journal-images')
 88→        .remove([...new Set(normalizedPaths)]);
 89→
 90→    if(error){
