 98→            <div className="chapter-manager">
 99→                <p className="chapter-manager-error">Story not found.</p>
100→            </div>
101→        );
102→    }
103→
104→    return (
105→        <motion.div
106→            className="chapter-manager"
107→            initial={{ opacity: 0, y: 12 }}
